# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

@Library('shared-library') _

properties([
    parameters([
        string(name: 'ARTIFACT_URL', defaultValue: '', description: 'URL to download the artifact from (S3, Artifactory, HTTP/HTTPS)'),
        string(name: 'ARTIFACT_NAME', defaultValue: 'application.jar', description: 'Name to save the artifact as'),
        choice(name: 'ENVIRONMENT', choices: ['staging', 'production'], description: 'Target environment'),
        string(name: 'DEPLOYMENT_SERVERS', defaultValue: '', description: 'Comma-separated list of servers (e.g., server1.com,server2.com)'),
        string(name: 'DEPLOYMENT_PATH', defaultValue: '/opt/application', description: 'Path on target servers to deploy artifact'),
        string(name: 'SERVICE_NAME', defaultValue: 'application', description: 'Service name to restart after deployment'),
        booleanParam(name: 'BACKUP_EXISTING', defaultValue: true, description: 'Backup existing artifact before deployment'),
        booleanParam(name: 'VERIFY_CHECKSUM', defaultValue: true, description: 'Verify artifact checksum if available'),
        string(name: 'CHECKSUM_URL', defaultValue: '', description: 'URL to checksum file (optional)'),
        choice(name: 'CHECKSUM_TYPE', choices: ['sha256', 'sha1', 'md5'], description: 'Checksum algorithm'),
        string(name: 'S3_CREDENTIALS_ID', defaultValue: 'aws-credentials', description: 'AWS credentials ID for S3 downloads'),
        string(name: 'ARTIFACTORY_CREDENTIALS_ID', defaultValue: 'artifactory-credentials', description: 'Artifactory credentials ID'),
        string(name: 'SSH_CREDENTIALS_ID', defaultValue: 'ssh-deploy-key', description: 'SSH credentials for deployment'),
        booleanParam(name: 'ROLLING_DEPLOYMENT', defaultValue: true, description: 'Deploy to servers one at a time'),
        string(name: 'HEALTH_CHECK_URL', defaultValue: '', description: 'Health check URL path (e.g., /health)'),
        string(name: 'HEALTH_CHECK_TIMEOUT', defaultValue: '300', description: 'Health check timeout in seconds'),
        booleanParam(name: 'DRY_RUN', defaultValue: false, description: 'Perform dry run without actual deployment')
    ])
])

pipeline {
    agent any
    
    environment {
        ARTIFACT_DIR = "${WORKSPACE}/artifacts"
        DEPLOYMENT_LOG = "${WORKSPACE}/deployment.log"
        TIMESTAMP = sh(script: "date +%Y%m%d_%H%M%S", returnStdout: true).trim()
    }
    
    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    echo "Validating deployment parameters..."
                    
                    if (!params.ARTIFACT_URL) {
                        error("ARTIFACT_URL parameter is required")
                    }
                    
                    if (!params.DEPLOYMENT_SERVERS) {
                        error("DEPLOYMENT_SERVERS parameter is required")
                    }
                    
                    def urlPattern = ~/^(https?|s3|ftp):\/\/.+/
                    if (!params.ARTIFACT_URL.matches(urlPattern)) {
                        error("Invalid ARTIFACT_URL format. Must start with http://, https://, s3://, or ftp://")
                    }
                    
                    echo "Environment: ${params.ENVIRONMENT}"
                    echo "Artifact URL: ${params.ARTIFACT_URL}"
                    echo "Target Servers: ${params.DEPLOYMENT_SERVERS}"
                    echo "Deployment Path: ${params.DEPLOYMENT_PATH}"
                    
                    if (params.DRY_RUN) {
                        echo "*** DRY RUN MODE - No actual deployment will occur ***"
                    }
                }
            }
        }
        
        stage('Prepare Workspace') {
            steps {
                script {
                    echo "Preparing workspace..."
                    sh """
                        mkdir -p ${ARTIFACT_DIR}
                        rm -f ${ARTIFACT_DIR}/*
                        touch ${DEPLOYMENT_LOG}
                    """
                }
            }
        }
        
        stage('Download Artifact') {
            steps {
                script {
                    echo "Downloading artifact from ${params.ARTIFACT_URL}..."
                    
                    def artifactPath = "${ARTIFACT_DIR}/${params.ARTIFACT_NAME}"
                    def url = params.ARTIFACT_URL
                    
                    if (url.startsWith('s3://')) {
                        downloadFromS3(url, artifactPath)
                    } else if (url.contains('artifactory')) {
                        downloadFromArtifactory(url, artifactPath)
                    } else if (url.startsWith('http://') || url.startsWith('https://')) {
                        downloadFromHttp(url, artifactPath)
                    } else if (url.startsWith('ftp://')) {
                        downloadFromFtp(url, artifactPath)
                    } else {
                        error("Unsupported URL protocol: ${url}")
                    }
                    
                    sh """
                        if [ ! -f ${artifactPath} ]; then
                            echo "ERROR: Artifact download failed"
                            exit 1
                        fi
                        
                        echo "Artifact downloaded successfully"
                        ls -lh ${artifactPath}
                    """
                }
            }
        }
        
        stage('Verify Checksum') {
            when {
                expression { params.VERIFY_CHECKSUM && params.CHECKSUM_URL }
            }
            steps {
                script {
                    echo "Verifying artifact checksum..."
                    
                    def checksumPath = "${ARTIFACT_DIR}/checksum.txt"
                    def artifactPath = "${ARTIFACT_DIR}/${params.ARTIFACT_NAME}"
                    
                    if (params.CHECKSUM_URL.startsWith('s3://')) {
                        downloadFromS3(params.CHECKSUM_URL, checksumPath)
                    } else {
                        sh "curl -sSL -o ${checksumPath} ${params.CHECKSUM_URL}"
                    }
                    
                    def expectedChecksum = sh(script: "cat ${checksumPath} | awk '{print \$1}'", returnStdout: true).trim()
                    def actualChecksum = ""
                    
                    switch(params.CHECKSUM_TYPE) {
                        case 'sha256':
                            actualChecksum = sh(script: "sha256sum ${artifactPath} | awk '{print \$1}'", returnStdout: true).trim()
                            break
                        case 'sha1':
                            actualChecksum = sh(script: "sha1sum ${artifactPath} | awk '{print \$1}'", returnStdout: true).trim()
                            break
                        case 'md5':
                            actualChecksum = sh(script: "md5sum ${artifactPath} | awk '{print \$1}'", returnStdout: true).trim()
                            break
                    }
                    
                    echo "Expected ${params.CHECKSUM_TYPE}: ${expectedChecksum}"
                    echo "Actual ${params.CHECKSUM_TYPE}: ${actualChecksum}"
                    
                    if (expectedChecksum != actualChecksum) {
                        error("Checksum verification failed! Expected: ${expectedChecksum}, Got: ${actualChecksum}")
                    }
                    
                    echo "Checksum verification passed"
                }
            }
        }
        
        stage('Deploy to Servers') {
            steps {
                script {
                    def servers = params.DEPLOYMENT_SERVERS.split(',').collect { it.trim() }
                    def artifactPath = "${ARTIFACT_DIR}/${params.ARTIFACT_NAME}"
                    
                    echo "Deploying to ${servers.size()} server(s)..."
                    
                    if (params.ROLLING_DEPLOYMENT) {
                        echo "Using rolling deployment strategy"
                        for (server in servers) {
                            deployToServer(server, artifactPath)
                        }
                    } else {
                        echo "Using parallel deployment strategy"
                        def deploymentSteps = [:]
                        
                        servers.each { server ->
                            deploymentSteps[server] = {
                                deployToServer(server, artifactPath)
                            }
                        }
                        
                        parallel deploymentSteps
                    }
                    
                    echo "Deployment completed successfully"
                }
            }
        }
        
        stage('Verify Deployment') {
            when {
                expression { params.HEALTH_CHECK_URL && !params.DRY_RUN }
            }
            steps {
                script {
                    def servers = params.DEPLOYMENT_SERVERS.split(',').collect { it.trim() }
                    def timeout = params.HEALTH_CHECK_TIMEOUT.toInteger()
                    
                    echo "Verifying deployment health checks..."
                    
                    servers.each { server ->
                        verifyServerHealth(server, timeout)
                    }
                    
                    echo "All health checks passed"
                }
            }
        }
    }
    
    post {
        success {
            script {
                echo "Deployment successful!"
                
                def deploymentInfo = """
                Deployment Summary:
                - Environment: ${params.ENVIRONMENT}
                - Artifact: ${params.ARTIFACT_NAME}
                - Source: ${params.ARTIFACT_URL}
                - Servers: ${params.DEPLOYMENT_SERVERS}
                - Timestamp: ${TIMESTAMP}
                - Status: SUCCESS
                """
                
                echo deploymentInfo
                writeFile file: "${WORKSPACE}/deployment-summary.txt", text: deploymentInfo
                archiveArtifacts artifacts: 'deployment-summary.txt', allowEmptyArchive: true
            }
        }
        
        failure {
            script {
                echo "Deployment failed!"
                
                def failureInfo = """
                Deployment Failed:
                - Environment: ${params.ENVIRONMENT}
                - Artifact: ${params.ARTIFACT_NAME}
                - Source: ${params.ARTIFACT_URL}
                - Servers: ${params.DEPLOYMENT_SERVERS}
                - Timestamp: ${TIMESTAMP}
                - Status: FAILED
                """
                
                echo failureInfo
                writeFile file: "${WORKSPACE}/deployment-failure.txt", text: failureInfo
                archiveArtifacts artifacts: 'deployment-failure.txt', allowEmptyArchive: true
            }
        }
        
        always {
            script {
                if (fileExists("${DEPLOYMENT_LOG}")) {
                    archiveArtifacts artifacts: 'deployment.log', allowEmptyArchive: true
                }
                
                cleanWs()
            }
        }
    }
}

def downloadFromS3(String s3Url, String destPath) {
    withCredentials([[$class: 'AmazonWebServicesCredentialsBinding', 
                      credentialsId: params.S3_CREDENTIALS_ID]]) {
        sh """
            aws s3 cp ${s3Url} ${destPath}
        """
    }
}

def downloadFromArtifactory(String url, String destPath) {
    withCredentials([usernamePassword(credentialsId: params.ARTIFACTORY_CREDENTIALS_ID, 
                                      usernameVariable: 'ARTIFACTORY_USER', 
                                      passwordVariable: 'ARTIFACTORY_PASSWORD')]) {
        sh """
            curl -u \${ARTIFACTORY_USER}:\${ARTIFACTORY_PASSWORD} -sSL -o ${destPath} ${url}
        """
    }
}

def downloadFromHttp(String url, String destPath) {
    sh """
        curl -sSL -o ${destPath} ${url}
        
        if [ \$? -ne 0 ]; then
            echo "ERROR: Failed to download from ${url}"
            exit 1
        fi
    """
}

def downloadFromFtp(String url, String destPath) {
    sh """
        curl -sSL -o ${destPath} ${url}
    """
}

def deployToServer(String server, String artifactPath) {
    echo "Deploying to server: ${server}"
    
    if (params.DRY_RUN) {
        echo "[DRY RUN] Would deploy ${artifactPath} to ${server}:${params.DEPLOYMENT_PATH}"
        return
    }
    
    sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
        def backupCmd = ""
        if (params.BACKUP_EXISTING) {
            backupCmd = """
                if [ -f ${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME} ]; then
                    echo "Backing up existing artifact..."
                    cp ${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME} ${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME}.backup.${TIMESTAMP}
                fi
            """
        }
        
        sh """
            echo "Connecting to ${server}..."
            
            ssh -o StrictHostKeyChecking=no ${server} '
                mkdir -p ${params.DEPLOYMENT_PATH}
                ${backupCmd}
            '
            
            echo "Copying artifact to ${server}..."
            scp -o StrictHostKeyChecking=no ${artifactPath} ${server}:${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME}
            
            echo "Setting permissions..."
            ssh -o StrictHostKeyChecking=no ${server} '
                chmod 644 ${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME}
            '
            
            echo "Restarting service ${params.SERVICE_NAME}..."
            ssh -o StrictHostKeyChecking=no ${server} '
                if command -v systemctl &> /dev/null; then
                    sudo systemctl restart ${params.SERVICE_NAME} || true
                elif command -v service &> /dev/null; then
                    sudo service ${params.SERVICE_NAME} restart || true
                else
                    echo "WARNING: Could not find systemctl or service command"
                fi
            '
            
            echo "Deployment to ${server} completed"
        """
    }
    
    sh "echo '${TIMESTAMP} - Deployed to ${server}' >> ${DEPLOYMENT_LOG}"
}

def verifyServerHealth(String server, Integer timeout) {
    echo "Checking health of ${server}..."
    
    def healthUrl = "http://${server}${params.HEALTH_CHECK_URL}"
    def startTime = System.currentTimeMillis()
    def endTime = startTime + (timeout * 1000)
    def healthy = false
    
    while (System.currentTimeMillis() < endTime && !healthy) {
        try {
            def response = sh(script: "curl -s -o /dev/null -w '%{http_code}' ${healthUrl}", returnStdout: true).trim()
            
            if (response == '200') {
                echo "Health check passed for ${server}"
                healthy = true
            } else {
                echo "Health check returned ${response}, retrying..."
                sleep(10)
            }
        } catch (Exception e) {
            echo "Health check failed: ${e.message}, retrying..."
            sleep(10)
        }
    }
    
    if (!healthy) {
        error("Health check failed for ${server} after ${timeout} seconds")
    }
}